SELECT id, user_id, product_id, quantity, total_price, status, create_time, update_time
FROM `order`
WHERE id = #{id}

SELECT id, user_id, product_id, quantity, total_price, status, create_time, update_time
FROM `order`
WHERE user_id = #{userId} AND product_id = #{productId}

mapper.update:
UPDATE `order`
SET status = #{status}, update_time = NOW()
WHERE id = #{orderId} AND status != #{status}
